$root=dirname(__DIR__);$release=null;foreach(array_slice($argv,1) as $arg)if(str_starts_with($arg,'--release='))$release=substr($arg,10);if(!$release){$matches=glob($root.'/storage/releases/*')?:[];usort($matches,static fn($a,$b)=>filemtime($b)<=>filemtime($a));$release=$matches[0]??null;}$release=$release?realpath($release):false;if(!$release||!is_file($release.'/catalog.json')||!is_dir($release.'/app'))throw new RuntimeException('Folder rilis tidak valid.');$app=$release.'/app';$runtime=$app;if(is_file($runtime.'/config/app.php')||is_file($runtime.'/storage/installed.lock'))throw new RuntimeException('Rilis membawa konfigurasi atau lock instalasi.');$catalog=json_decode((string)file_get_contents($release.'/catalog.json'),true,32,JSON_THROW_ON_ERROR);foreach($catalog['modules'] as $module=>$package){$path=$release.'/'.$package['file'];if(!is_file($path)||!hash_equals($package['sha256'],hash_file('sha256',$path)))throw new RuntimeException('Checksum katalog gagal: '.$module);}
